import styled from "styled-components";

export const Container = styled.div`
    display: block;
    width: 100%;
    height: 90%;
`;

export const Label = styled.label`
    display: inline-flex;
    font-size: 1.7em;
    margin-right: 10px;
    padding: 5px;
`;

export const Input = styled.input`
    font-size: 1.7em;
    border: 1px solid transparent;
    border-radius: 5px;
    padding: 5px;

`;
